import{a5 as t,L as o,X as a,aJ as s}from"./chunks/framework.DiqW36cl.js";const m=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md","lastUpdated":1782138787000}'),n={name:"getting-started/index.md"};function r(i,e,c,l,d,h){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>vuecs</strong> is a Vue 3 <strong>theming framework with shipped components</strong>. Reframed: the components are the obvious surface, but the theming machinery underneath them is the value. Three layers:</p><ol><li><p><strong>Theming machinery</strong> (<code>@vuecs/core</code>). Every component reads its CSS classes through a four-layer resolution chain (defaults → themes → overrides → instance props) with structured variants and compound variants. The same machinery is exported for <strong>third-party use</strong> — your own <code>&lt;MyDataTable&gt;</code> registers a theme slot via <code>ThemeElements</code> declaration merging and resolves through the same manager that vuecs&#39;s primitives use. Consumers re-skin everything (vuecs + your library) through one <code>app.use(vuecs, …)</code> call.</p></li><li><p><strong>Design tokens + runtime palette switching.</strong> Colors, radii, and semantic aliases live in CSS custom properties in <code>@vuecs/design</code> (concrete OKLCH defaults — works with or without Tailwind). <code>useColorPalette()</code> from <code>@vuecs/design</code> dispatches through whichever themes the app installs; a one-line <code>useColorPalette().set({ primary: &#39;green&#39; })</code> re-tints every component on the page with no Vue re-render. <code>@vuecs/theme-tailwind</code> and <code>@vuecs/theme-bulma</code> contribute their renderers (<code>palette.handle</code>) against the <strong>same 22-name palette catalog</strong> — Bulma renders those names as HSL channel vars internally, but the stored payload is interchangeable across themes (so a single picker UI drives both).</p></li><li><p><strong>SSR-safe Nuxt integration.</strong> <code>@vuecs/nuxt</code> wires color-mode + palette plumbing into Nuxt&#39;s <code>&lt;head&gt;</code> on the server, so first paint matches what the client computes — no FOUC, no hydration mismatch. One theme-agnostic module covers every theme; the runtime dispatches through whichever themes you install.</p></li></ol><h2 id="why-another-component-library" tabindex="-1">Why another component library? <a class="header-anchor" href="#why-another-component-library" aria-label="Permalink to &quot;Why another component library?&quot;">​</a></h2><p>Because vuecs isn&#39;t (just) a component library. Most libraries pick a CSS framework upfront and bake it in. vuecs treats themes as <strong>data</strong>: a theme is a function returning a class-map, merged in array order against component defaults. That has two consequences:</p><ul><li>The same component renders correctly under Tailwind v4, Bootstrap 5, or Bulma 1.0+ — pick at consume time. Override individual slot classes via <code>app.use(vuecs, { overrides: ... })</code> or per-instance via <code>themeClass</code> / <code>themeVariant</code> props.</li><li><strong>You can build on the same theme system.</strong> A library author drops <code>useComponentTheme</code> into their own components, and downstream consumers reskin the union (vuecs + that library) with one config call. No fork; no parallel theme system.</li></ul><h2 id="what-s-in-the-box" tabindex="-1">What&#39;s in the box <a class="header-anchor" href="#what-s-in-the-box" aria-label="Permalink to &quot;What&#39;s in the box&quot;">​</a></h2><ul><li><strong>Components</strong> — button, navigation (incl. stepper), pagination, forms (checkbox / switch / input / number / pin / radio / select / select-search / slider / tags / textarea), list, overlays (modal / popover / hover-card / tooltip / dropdown-menu / context-menu), elements (separator / tag / avatar / aspect-ratio / visually-hidden / badge), countdown, gravatar, link, timeago, icon.</li><li><strong>Themes</strong> — <code>@vuecs/theme-tailwind</code>, <code>@vuecs/theme-bootstrap</code>, <code>@vuecs/theme-bulma</code>. Cosmetic adapters that compose with the design-token layer.</li><li><strong>Icons</strong> — <code>@vuecs/icon</code> (<code>&lt;VCIcon&gt;</code>, Iconify-backed) plus presets (<code>@vuecs/icons-lucide</code>, <code>@vuecs/icons-font-awesome</code>) that map vuecs&#39;s semantic-slot defaults to specific icon vocabularies.</li><li><strong>Design tokens</strong> — <code>@vuecs/design</code> ships CSS variables, theme-aware <code>useColorPalette()</code>, and generic palette primitives.</li><li><strong>Runtime palette</strong> — <code>useColorPalette()</code> from <code>@vuecs/design</code> dispatches through installed themes&#39; <code>palette.handle</code> hooks. <code>@vuecs/theme-tailwind</code> and <code>@vuecs/theme-bulma</code> each contribute a renderer against the <strong>shared 22-name Tailwind palette catalog</strong> (Bulma renders those names as HSL channel vars internally — payload is interchangeable, so a single picker UI drives both).</li><li><strong>Nuxt module</strong> — <code>@vuecs/nuxt</code> ships tokens + SSR-safe color mode + SSR-safe palette in one theme-agnostic module.</li><li><strong>Example apps</strong> — one Nuxt + three vanilla Vite + Vue 3 (Tailwind, Bootstrap, Bulma), all consuming a shared private workspace package of demo views. See <code>examples/</code> in the repo.</li></ul><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/getting-started/installation">Installation</a> — install packages and wire the plugin.</li><li><a href="/getting-started/theming">Theming</a> — pick a theme, override slot classes, switch palette at runtime.</li><li><a href="/getting-started/dark-mode">Dark Mode</a> — toggle <code>.dark</code> and let the design tokens flip everything.</li><li><a href="/components/">Components</a> — browse the component catalog with live demos.</li></ul>',10)])])}const p=t(n,[["render",r]]);export{m as __pageData,p as default};
